import{_ as s,c as a,o as e,aj as p}from"./chunks/framework.Cjb08o0w.js";const h=JSON.parse('{"title":"Jenkins","description":"","frontmatter":{"date":"","draft":false,"title":"Jenkins"},"headers":[],"relativePath":"computer-science/CI-CD/jenkins.md","filePath":"computer-science/CI-CD/jenkins.md"}'),l={name:"computer-science/CI-CD/jenkins.md"};function i(r,n,c,t,o,k){return e(),a("div",null,[...n[0]||(n[0]=[p(`<h1 id="jenkins" tabindex="-1">Jenkins <a class="header-anchor" href="#jenkins" aria-label="Permalink to “Jenkins”">​</a></h1><ul><li><a href="https://www.jenkins.io/doc/book/installing/" target="_blank" rel="noreferrer">docs</a><ul><li><a href="https://www.jenkins.io/doc/book/installing/docker/" target="_blank" rel="noreferrer">docker</a></li><li><a href="https://www.jenkins.io/doc/book/installing/macos/" target="_blank" rel="noreferrer">macOS</a><ul><li><a href="https://www.jenkins.io/download/lts/macos/" target="_blank" rel="noreferrer">macOS Installer for Jenkins LTS</a><ul><li>Install the latest LTS version: <code>brew install jenkins-lts</code></li><li>Start the Jenkins service: <code>brew services start jenkins-lts</code></li><li>Restart the Jenkins service: <code>brew services restart jenkins-lts</code></li><li>Update the Jenkins version: <code>brew upgrade jenkins-lts</code></li></ul></li></ul></li><li><a href="https://www.jenkins.io/doc/book/using/" target="_blank" rel="noreferrer">Using Jenkins</a></li></ul></li><li><a href="https://github.com/jenkins-zh/jenkins-client-java" target="_blank" rel="noreferrer">jenkins-zh/jenkins-client-java</a><ul><li>Java实现的对Jenkins操作</li></ul></li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to “安装”">​</a></h2><h3 id="docker-安装" tabindex="-1">docker 安装 <a class="header-anchor" href="#docker-安装" aria-label="Permalink to “docker 安装”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># pull</span></span>
<span class="line"><span>docker pull jenkins/jenkins:2.516.1-lts-jdk17</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 准备目录</span></span>
<span class="line"><span>mkdir -p /opt/jenkins</span></span>
<span class="line"><span>mkdir -p /data/jenkins</span></span>
<span class="line"><span>chown -R 1000:1000 /data/jenkins</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 进入目录</span></span>
<span class="line"><span>cd /opt/jenkins</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 创建 compose.yaml</span></span>
<span class="line"><span>vim compose.yaml</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 写入</span></span>
<span class="line"><span>services:</span></span>
<span class="line"><span>  jenkins:</span></span>
<span class="line"><span>    image: jenkins/jenkins:2.516.1-lts-jdk17</span></span>
<span class="line"><span>    container_name: jenkins</span></span>
<span class="line"><span>    restart: unless-stopped</span></span>
<span class="line"><span>    ports:</span></span>
<span class="line"><span>      - &quot;8080:8080&quot;</span></span>
<span class="line"><span>      - &quot;50000:50000&quot;</span></span>
<span class="line"><span>    environment:</span></span>
<span class="line"><span>      - TZ=Asia/Shanghai</span></span>
<span class="line"><span>    volumes:</span></span>
<span class="line"><span>      - /data/jenkins:/var/jenkins_home</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 启动 Jenkins</span></span>
<span class="line"><span># 先试这个</span></span>
<span class="line"><span>docker compose up -d</span></span>
<span class="line"><span># 如果提示没有 docker compose，再用旧命令</span></span>
<span class="line"><span>docker-compose up -d</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 查看状态</span></span>
<span class="line"><span>docker ps</span></span>
<span class="line"><span># 或者</span></span>
<span class="line"><span>docker compose ps</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 看日志</span></span>
<span class="line"><span>docker logs -f jenkins</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 获取初始化密码</span></span>
<span class="line"><span>docker exec jenkins cat /var/jenkins_home/secrets/initialAdminPassword</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 然后浏览器访问</span></span>
<span class="line"><span>http://服务器IP:8080</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 以后怎么停止、启动、重启</span></span>
<span class="line"><span># 进入目录：</span></span>
<span class="line"><span>cd /opt/jenkins</span></span>
<span class="line"><span># 停止：</span></span>
<span class="line"><span>docker compose down</span></span>
<span class="line"><span># 启动：</span></span>
<span class="line"><span>docker compose up -d</span></span>
<span class="line"><span># 重启：</span></span>
<span class="line"><span>docker compose restart</span></span>
<span class="line"><span># 查看日志：</span></span>
<span class="line"><span>docker compose logs -f</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 以后升级 Jenkins</span></span>
<span class="line"><span># 比如以后要升级到新版本，只需要改：</span></span>
<span class="line"><span># image: jenkins/jenkins:2.516.1-lts-jdk17</span></span>
<span class="line"><span># 改成新版本，然后执行：</span></span>
<span class="line"><span>cd /opt/jenkins</span></span>
<span class="line"><span>docker compose pull</span></span>
<span class="line"><span>docker compose down</span></span>
<span class="line"><span>docker compose up -d</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span># 备份 Jenkins</span></span>
<span class="line"><span># Jenkins 的核心数据都在：/data/jenkins</span></span>
<span class="line"><span># 备份：</span></span>
<span class="line"><span>tar -czvf /root/jenkins-backup-$(date +%F).tar.gz /data/jenkins</span></span></code></pre></div><h4 id="compose-yml" tabindex="-1">compose.yml <a class="header-anchor" href="#compose-yml" aria-label="Permalink to “compose.yml”">​</a></h4><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span></span></span></code></pre></div><h2 id="password" tabindex="-1">password <a class="header-anchor" href="#password" aria-label="Permalink to “password”">​</a></h2><ul><li><a href="https://ask.csdn.net/questions/4645065" target="_blank" rel="noreferrer">jenkins publish over SSH中SSH sever密码存放位置</a></li><li><a href="https://blog.csdn.net/qq_27156945/article/details/108083342" target="_blank" rel="noreferrer">记录 从jenkins配置文件中解密密码</a></li></ul><h2 id="磁盘空间" tabindex="-1">磁盘空间 <a class="header-anchor" href="#磁盘空间" aria-label="Permalink to “磁盘空间”">​</a></h2><ul><li><a href="https://developer.aliyun.com/article/1195696" target="_blank" rel="noreferrer">Jenkins Jenkins构建历史记录处理</a></li></ul><h2 id="reference" tabindex="-1">reference <a class="header-anchor" href="#reference" aria-label="Permalink to “reference”">​</a></h2><ul><li><a href="https://blog.csdn.net/shuang_waiwai/article/details/121124203" target="_blank" rel="noreferrer">在Jenkins中拉取GitHub上的代码包（超详细)</a></li><li><a href="https://blog.csdn.net/u012045045/article/details/107126372" target="_blank" rel="noreferrer">jenkins配置全局凭据 结合gitlab</a></li><li><a href="https://www.cnblogs.com/dingshaohua/p/16458325.html" target="_blank" rel="noreferrer">jenkins部署github项目</a></li></ul>`,13)])])}const m=s(l,[["render",i]]);export{h as __pageData,m as default};
